input.command:
for pod in mongodb-replica-0 mongodb-replica-1 mongodb-replica-2; do
  echo "=== $pod ==="
  kubectl exec -n mongodb "$pod" -- mongosh --quiet "mongodb://admin-user:admin123password@localhost:27017/admin?directConnection=true" --eval "
    var o = db.adminCommand({getCmdLineOpts:1}).parsed || {};
    var v = (o.systemLog && o.systemLog.verbosity != null) ? o.systemLog.verbosity : db.adminCommand({getParameter:1,logLevel:1}).logLevel;
    var s = (o.operationProfiling && o.operationProfiling.slowOpThresholdMs != null) ? o.operationProfiling.slowOpThresholdMs : db.getProfilingStatus().slowms;
    var c = (o.storage && o.storage.wiredTiger && o.storage.wiredTiger.engineConfig) ? o.storage.wiredTiger.engineConfig.journalCompressor : 'unknown';
    print('verbosity=' + v + ' slowms=' + s + ' journalCompressor=' + c);
  " 2>&1
done
